//承認済みチャット一覧 API
import { NextResponse } from "next/server";
import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient();

export async function GET(request: Request) {
  // 本来はログイン中のPTのIDを使いますが、デモ用に全承認済みマッチを取得
  try {
    const approvedMatches = await (prisma as any).matchRequest.findMany({
      where: { status: "APPROVED" },
      include: { user: true } // 利用者の名前や悩みも一緒に持ってくる
    });
    return NextResponse.json(approvedMatches);
  } catch (error) {
    return NextResponse.json({ message: "取得失敗" }, { status: 500 });
  }
}